TRAINT [CK__Oferta_Es__Estad__412EB0B6] CHECK  (([Estado]='Fechada' OR [Estado]='Ativa'))\r\n","GO\r\n","ALTER TABLE [dbo].[Oferta_Estagio] CHECK CONSTRAINT [CK__Oferta_Es__Estad__412EB0B6]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/Table[@Name='Oferta_Estagio' and @Schema='dbo']/Check[@Name='CK__Oferta_Es__Estad__412EB0B6']","object_type":"Check"}},{"cell_type":"markdown","source":["# [CK_Datas_Validas]"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/Table[@Name='Oferta_Estagio' and @Schema='dbo']/Check[@Name='CK_Datas_Validas']","object_type":"Check"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[Oferta_Estagio]  WITH CHECK ADD  CONSTRAINT [CK_Datas_Validas] CHECK  (([Data_Limite]>=CONVERT([date],[Data_Publicacao])))\r\n","GO\r\n","ALTER TABLE [dbo].[Oferta_Estagio] CHECK CONSTRAINT [CK_Datas_Validas]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/Table[@Name='Oferta_Estagio' and @Schema='dbo']/Check[@Name='CK_Datas_Validas']","object_type":"Check"}},{"cell_type":"markdown","source":["# [CK_LimiteVagas]"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/Table[@Name='Oferta_Estagio' and @Schema='dbo']/Check[@Name='CK_LimiteVagas']","object_type":"Check"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[Oferta_Estagio]  WITH CHECK ADD  CONSTRAINT [CK_LimiteVagas] CHECK  (([Vagas_Ocupadas]<=[N_Vagas]))\r\n","GO\r\n","ALTER TABLE [dbo].[Oferta_Estagio] CHECK CONSTRAINT [CK_LimiteVagas]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/Table[@Name='Oferta_Estagio' and @Schema='dbo']/Check[@Name='CK_LimiteVagas']","object_type":"Check"}},{"cell_type":"markdown","source":["# [dbo].[SP_AtualizarEstadoCandidatura]"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_AtualizarEstadoCandidatura' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[SP_AtualizarEstadoCandidatura]    Script Date: 24/02/2026 18:59:43 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[SP_AtualizarEstadoCandidatura]\r\n    @Id_Candidatura INT,\r\n    @NovoEstado NVARCHAR(10),\r\n    @OBS NVARCHAR(200) = NULL\r\nAS\r\nBEGIN\r\n    SET NOCOUNT ON;\r\n    DECLARE @EstadoAnterior NVARCHAR(10);\r\n    -- Validações\r\n    IF @NovoEstado NOT IN ('ACEITE', 'RECUSADO', 'PENDENTE')\r\n    BEGIN\r\n        RAISERROR('Erro: Estado inválido.', 16, 1);\r\n        RETURN;\r\n    END\r\n\r\n    SELECT @EstadoAnterior = Estado \r\n    FROM Candidatura \r\n    WHERE Id_Candidatura = @Id_Candidatura;\r\n\r\n    IF @EstadoAnterior IS NULL\r\n    BEGIN\r\n        RAISERROR('Erro: Candidatura não encontrada.', 16, 1);\r\n        RETURN;\r\n    END\r\n\r\n    UPDATE Candidatura\r\n    SET Estado = @NovoEstado,\r\n        OBS = @OBS -- opcional\r\n    WHERE Id_Candidatura = @Id_Candidatura;\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_AtualizarEstadoCandidatura' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[SP_CriarOfertaEstagio]"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_CriarOfertaEstagio' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[SP_CriarOfertaEstagio]    Script Date: 24/02/2026 18:59:43 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","--2. (depende da view vw_EmpresasAtivas)\r\nCREATE PROCEDURE [dbo].[SP_CriarOfertaEstagio]\r\n    @Id_Empresa INT,\r\n    @Titulo VARCHAR(50),\r\n    @Descricao NVARCHAR(200) = NULL,\r\n    @N_Vagas INT,\r\n    @Data_Limite DATE = NULL\r\nAS\r\nBEGIN\r\n    IF @Id_Empresa IS NULL\r\n        PRINT 'Id_Empresa é obrigatório.'\r\n    ELSE IF NOT EXISTS (SELECT * FROM vw_EmpresasAtivas WHERE Id = @Id_Empresa)\r\n        PRINT 'Empresa inválida ou inativa.'\r\n    ELSE IF @Titulo IS NULL\r\n        PRINT 'Título é obrigatório.'\r\n    ELSE IF @N_Vagas IS NULL OR @N_Vagas <= 0\r\n        PRINT 'Número de vagas inválido.'\r\n    ELSE\r\n    BEGIN\r\n        INSERT INTO Oferta_Estagio\r\n            (Titulo, Descricao, Estado, N_Vagas, Vagas_Ocupadas, Data_Publicacao, Data_Limite, Id_Empresa)\r\n        VALUES\r\n            (@Titulo, @Descricao, 'ATIVA', @N_Vagas, 0, GETDATE(), @Data_Limite, @Id_Empresa)\r\n\r\n        PRINT 'Oferta criada com sucesso.'\r\n    END\r\nEND\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_CriarOfertaEstagio' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[SP_EstagiosComMaisProcura]"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_EstagiosComMaisProcura' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[SP_EstagiosComMaisProcura]    Script Date: 24/02/2026 18:59:43 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[SP_EstagiosComMaisProcura]\r\nAS\r\nBEGIN\r\n    SELECT\r\n        O.Id_Estagio,\r\n        O.Titulo,\r\n        E.Nome AS Empresa,\r\n        COUNT(C.Id_Candidatura) AS Total_Candidaturas\r\n    FROM Oferta_Estagio O, Empresa E, Candidatura C\r\n    WHERE O.Id_Empresa = E.Id\r\n      AND C.Id_Estagio = O.Id_Estagio\r\n    GROUP BY O.Id_Estagio, O.Titulo, E.Nome\r\n    ORDER BY Total_Candidaturas DESC\r\nEND\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_EstagiosComMaisProcura' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[SP_EstatisticasGerais]"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_EstatisticasGerais' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[SP_EstatisticasGerais]    Script Date: 24/02/2026 18:59:43 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[SP_EstatisticasGerais]\nAS\nBEGIN\n    SELECT\n        (SELECT COUNT(*) FROM Aluno) AS Total_Alunos,\n        (SELECT COUNT(*) FROM Empresa) AS Total_Empresas,\n        (SELECT COUNT(*) FROM Oferta_Estagio) AS Total_Ofertas,\n\n        (SELECT COUNT(*) FROM Oferta_Estagio WHERE Estado = 'ATIVA') AS Ofertas_Ativas,\n        (SELECT COUNT(*) FROM Oferta_Estagio WHERE Estado = 'FECHADA') AS Ofertas_Fechadas,\n\n        (SELECT COUNT(*)\n         FROM Oferta_Estagio\n         WHERE Estado = 'ATIVA'\n            AND N_Vagas IS NOT NULL\n            AND Vagas_Ocupadas IS NOT NULL\n            AND Vagas_Ocupadas < N_Vagas\n            AND (Data_Limite IS NULL OR Data_Limite >= CONVERT(date, GETDATE()))\n        ) AS Ofertas_Disponiveis,\n\n        (SELECT COUNT(*) FROM Candidatura) AS Total_Candidaturas,\n        (SELECT COUNT(*) FROM Candidatura WHERE Estado = 'PENDENTE') AS Candidaturas_Pendentes,\n        (SELECT COUNT(*) FROM Candidatura WHERE Estado = 'ACEITE') AS Candidaturas_Aceites,\n        (SELECT COUNT(*) FROM Candidatura WHERE Estado = 'RECUSADO') AS Candidaturas_Recusadas\nEND\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_EstatisticasGerais' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[SP_ListarCandidaturasPorAluno]"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_ListarCandidaturasPorAluno' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[SP_ListarCandidaturasPorAluno]    Script Date: 24/02/2026 18:59:43 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[SP_ListarCandidaturasPorAluno]\n    @N_Aluno INT\nAS\nBEGIN\n    IF NOT EXISTS (SELECT * FROM Aluno WHERE Numero = @N_Aluno)\n        PRINT 'Aluno não existe.'\n    ELSE\n        SELECT\n            C.Id_Candidatura,\n            C.Data_Submissao,\n            C.Estado,\n            C.OBS,\n            O.Id_Estagio,\n            O.Titulo,\n            E.Nome AS Empresa\n        FROM Candidatura C, Oferta_Estagio O, Empresa E\n        WHERE C.N_Aluno = @N_Aluno\n            AND O.Id_Estagio = C.Id_Estagio\n            AND E.Id = O.Id_Empresa\n        ORDER BY C.Data_Submissao DESC\nEND\n\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_ListarCandidaturasPorAluno' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[SP_ListarCandidaturasPorEmpresa]"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_ListarCandidaturasPorEmpresa' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[SP_ListarCandidaturasPorEmpresa]    Script Date: 24/02/2026 18:59:43 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[SP_ListarCandidaturasPorEmpresa]\r\n    @Id_Empresa INT\r\nAS\r\nBEGIN\r\n    IF NOT EXISTS (SELECT * FROM Empresa WHERE Id = @Id_Empresa)\r\n        PRINT 'Empresa não existe.'\r\n    ELSE\r\n        SELECT\r\n            C.Id_Candidatura,\r\n            C.Data_Submissao,\r\n            C.Estado,\r\n            A.Numero AS N_Aluno,\r\n            A.Nome AS Nome_Aluno,\r\n            O.Id_Estagio,\r\n            O.Titulo\r\n        FROM Oferta_Estagio O, Candidatura C, Aluno A\r\n        WHERE O.Id_Empresa = @Id_Empresa\r\n          AND C.Id_Estagio = O.Id_Estagio\r\n          AND A.Numero = C.N_Aluno\r\n        ORDER BY C.Data_Submissao DESC\r\nEND\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_ListarCandidaturasPorEmpresa' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[SP_ListarOfertasAtivas]"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_ListarOfertasAtivas' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[SP_ListarOfertasAtivas]    Script Date: 24/02/2026 18:59:43 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[SP_ListarOfertasAtivas]\r\nAS\r\nBEGIN\r\n    SELECT\r\n        O.Id_Estagio,\r\n        O.Titulo,\r\n        O.Descricao,\r\n        O.Data_Publicacao,\r\n        O.Data_Limite,\r\n        O.N_Vagas,\r\n        O.Vagas_Ocupadas,\r\n        (O.N_Vagas - O.Vagas_Ocupadas) AS Vagas_Disponiveis,\r\n        E.Nome AS Empresa\r\n    FROM Oferta_Estagio O, Empresa E\r\n    WHERE O.Id_Empresa = E.Id\r\n      AND O.Estado = 'ATIVA'\r\n      AND O.N_Vagas IS NOT NULL\r\n      AND O.Vagas_Ocupadas IS NOT NULL\r\n      AND O.Vagas_Ocupadas < O.N_Vagas\r\n      AND (O.Data_Limite IS NULL OR O.Data_Limite >= CONVERT(date, GETDATE()))\r\n    ORDER BY O.Data_Publicacao DESC\r\nEND\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']/StoredProcedure[@Name='SP_ListarOfertasAtivas' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [Ofertas_Estagios]"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']","object_type":"Database"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["USE [master]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']","object_type":"Database"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER DATABASE [Ofertas_Estagios] SET  READ_WRITE \r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Andarilh4\\SQLEXPRESS']/Database[@Name='Ofertas_Estagios']","object_type":"Database"}}]}